The viewer can be switched to manifest-based study discovery with a small change in [viewer.html](viewer.html) and one new manifest file in the studies data folder.

### 1) Replace the directory-listing loader in [viewer.html](viewer.html)

Use this in place of the current study discovery block:

```js
async function getStudyManifest() {
    const response = await fetch(
        "./data/bible_studies/manifest.json?cacheBust=" + Date.now()
    );

    if (!response.ok) {
        throw new Error(`Unable to load study manifest: ${response.status}`);
    }

    const manifest = await response.json();

    if (!Array.isArray(manifest)) {
        throw new Error("Study manifest is not an array");
    }

    return manifest
        .filter((entry) => entry && typeof entry.id === "string" && entry.id)
        .sort((a, b) => a.id.localeCompare(b.id));
}

async function getStudyIds() {
    const manifest = await getStudyManifest();
    return manifest.map((study) => study.id);
}
```

### 2) Update initialization in [viewer.html](viewer.html)

Replace the existing init logic that builds the select options from folder probing:

```js
async function init() {
    initDebugOverlay();

    const studySelect = document.getElementById("studySelect");
    if (!studySelect) {
        throw new Error("studySelect missing — study-toolbar DOM not loaded correctly");
    }

    const studyManifest = await getStudyManifest();
    studySelect.innerHTML = "";

    for (const study of studyManifest) {
        const option = document.createElement("option");
        option.value = study.id;
        option.textContent = study.title || study.id;
        studySelect.appendChild(option);
    }

    studySelect.addEventListener("change", () => {
        loadSelectedStudy();
    });

    if (studyManifest.length) {
        studySelect.value = studyManifest[0].id;
        await loadSelectedStudy();
    }
}
```

### 3) Create the manifest file

Add a manifest file in the studies data folder with the studies that currently have matching main JSON files:

```json
[
  { "id": "body_of_christ", "title": "The Body of Christ" },
  { "id": "bride_bridegroom", "title": "The Bride and Bridegroom" },
  { "id": "end_times", "title": "End Times - Last Days" },
  { "id": "firstborn_son", "title": "God's Firstborn Son" },
  { "id": "listen_hear", "title": "Listen - Hear - Act" },
  { "id": "sinful_nature", "title": "Sinful Nature" }
]
```

### 4) Optional generator for future updates

If you want to regenerate the manifest from the existing folders later, this script will do it:

```js
const fs = require("fs");
const path = require("path");

const studiesDir = path.join(__dirname, "data", "bible_studies");
const entries = fs.readdirSync(studiesDir, { withFileTypes: true })
  .filter((entry) => entry.isDirectory())
  .map((entry) => entry.name)
  .filter((id) => fs.existsSync(path.join(studiesDir, id, `${id}.json`)))
  .map((id) => ({ id, title: id.replace(/_/g, " ").replace(/\b\w/g, (c) => c.toUpperCase()) }));

fs.writeFileSync(
  path.join(studiesDir, "manifest.json"),
  JSON.stringify(entries, null, 2) + "\n",
  "utf8"
);
```

